function DelegationPanel({ onDelegate }) {
  const [delegateTo, setDelegateTo] = useState('');
  const [until, setUntil] = useState('');

  const handleActivate = () => {
    // Exact Delegate Payload match
    onDelegate(1, { 
      delegateTo: parseInt(delegateTo, 10), 
      comments: `Delegated until ${until}` 
    });
  };

  return (
    <div className="card" style={{ marginBottom: 16 }}>
      <div className="card-header"><div className="card-title"><Users size={15} style={{ marginRight: 6 }} />Approval Delegation</div></div>
